public class CustomCertificateValidator : X509CertificateValidator
{
    public override void Validate(X509Certificate2 certificate)
    {
        if (certificate == null)
            throw new ArgumentException("Certificate is null");
            
        // Validate certificate is not expired
        if (DateTime.Now > certificate.NotAfter)
            throw new SecurityTokenValidationException("Certificate has expired");
            
        if (DateTime.Now < certificate.NotBefore)
            throw new SecurityTokenValidationException("Certificate not yet valid");
            
        // Validate certificate chain
        X509Chain chain = new X509Chain();
        chain.Build(certificate);
        
        if (chain.ChainStatus.Length > 0)
            throw new SecurityTokenValidationException("Certificate chain validation failed");
    }
}

